namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new Recipe
        {
            Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
            Ingredients = "2 cups flour\n2 eggs\n1 cup milk\n2 tbsp sugar\n1 tsp baking powder",
            Steps = "1. Mix dry ingredients.\n2. Whisk eggs and milk together.\n3. Combine wet and dry.\n4. Cook on griddle until golden.",
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Dinner",
            Ingredients = "400g spaghetti\n200g pancetta\n4 egg yolks\n100g parmesan\nBlack pepper",
            Steps = "1. Cook pasta al dente.\n2. Fry pancetta until crispy.\n3. Mix yolks with parmesan.\n4. Toss hot pasta with pancetta, then egg mixture off heat.",
            AverageRating = 4.8, RatingCount = 24
        },
        new Recipe
        {
            Id = 3, Title = "Caesar Salad", Category = "Lunch",
            Ingredients = "1 romaine lettuce\nCroutons\nParmesan\nCaesar dressing\nGrilled chicken",
            Steps = "1. Chop lettuce.\n2. Toss with dressing.\n3. Top with croutons, parmesan, and chicken.",
            AverageRating = 4.0, RatingCount = 8
        },
        new Recipe
        {
            Id = 4, Title = "Chocolate Brownies", Category = "Desserts",
            Ingredients = "200g dark chocolate\n150g butter\n3 eggs\n200g sugar\n100g flour",
            Steps = "1. Melt chocolate and butter.\n2. Whisk eggs and sugar.\n3. Fold in chocolate mixture and flour.\n4. Bake at 180°C for 25 minutes.",
            AverageRating = 4.9, RatingCount = 30
        },
        new Recipe
        {
            Id = 5, Title = "Avocado Toast", Category = "Breakfast",
            Ingredients = "2 slices sourdough\n1 ripe avocado\nSalt and pepper\nChili flakes\nLemon juice",
            Steps = "1. Toast bread.\n2. Mash avocado with lemon, salt, pepper.\n3. Spread on toast.\n4. Sprinkle chili flakes.",
            AverageRating = 4.2, RatingCount = 15
        },
        new Recipe
        {
            Id = 6, Title = "Grilled Cheese Sandwich", Category = "Lunch",
            Ingredients = "2 slices bread\nButter\nCheddar cheese\nMozzarella",
            Steps = "1. Butter bread on outside.\n2. Layer cheeses inside.\n3. Grill on pan until golden and melted.",
            AverageRating = 4.3, RatingCount = 10
        },
        new Recipe
        {
            Id = 7, Title = "Chicken Stir Fry", Category = "Dinner",
            Ingredients = "500g chicken breast\nBell peppers\nSoy sauce\nGarlic\nGinger\nRice",
            Steps = "1. Slice chicken and vegetables.\n2. Stir fry chicken until cooked.\n3. Add vegetables, garlic, ginger.\n4. Add soy sauce. Serve over rice.",
            AverageRating = 4.4, RatingCount = 18
        },
        new Recipe
        {
            Id = 8, Title = "Tiramisu", Category = "Desserts",
            Ingredients = "500g mascarpone\n6 egg yolks\n100g sugar\nStrong coffee\nLadyfingers\nCocoa powder",
            Steps = "1. Whisk yolks and sugar.\n2. Fold in mascarpone.\n3. Dip ladyfingers in coffee.\n4. Layer with cream. Refrigerate overnight.\n5. Dust with cocoa.",
            AverageRating = 4.7, RatingCount = 22
        }
    ];

    private int _nextId = 9;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars is < 1 or > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }
}

