@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var line in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@line</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@StripNumberPrefix(step)</li>
        }
    </ol>

    <h3>Rating</h3>
    <p>@Recipe.AverageRating ★ (@Recipe.RatingCount ratings)</p>

    <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />

    <a href="category/@Recipe.Category" class="btn btn-link mt-3">← Back to @Recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] public RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }

    private static string StripNumberPrefix(string step)
    {
        var trimmed = step.TrimStart();
        if (trimmed.Length > 1 && char.IsDigit(trimmed[0]) && trimmed[1] == '.')
            return trimmed[2..].TrimStart();
        return trimmed;
    }
}

